    public function save_upload_fields($user_id) {
        if (!current_user_can('edit_user', $user_id)) {
            return false;
        }
        
        if (isset($_POST['delete_profile_picture']) && $_POST['delete_profile_picture'] == '1') {
            $old_picture = get_user_meta($user_id, 'user_profile_picture', true);
            if ($old_picture && file_exists($old_picture)) {
                unlink($old_picture);
            }
            delete_user_meta($user_id, 'user_profile_picture');
        }
        
        if (isset($_FILES['profile_picture']) && $_FILES['profile_picture']['error'] == 0) {
            $old_picture = get_user_meta($user_id, 'user_profile_picture', true);
            if ($old_picture && file_exists($old_picture)) {
                unlink($old_picture);
            }
            
            $uploaded_file = $this->handle_file_upload($_FILES['profile_picture'], $user_id, 'image');
            if ($uploaded_file) {
                update_user_meta($user_id, 'user_profile_picture', $uploaded_file);
            }
        }
        
        $existing_documents = get_user_meta($user_id, 'user_documents', true);
        if (!is_array($existing_documents)) {
            $existing_documents = array();
        }
        
        if (isset($_POST['delete_documents']) && is_array($_POST['delete_documents'])) {
            foreach ($_POST['delete_documents'] as $index) {
                if (isset($existing_documents[$index]) && file_exists($existing_documents[$index])) {
                    unlink($existing_documents[$index]);
                    unset($existing_documents[$index]);
                }
            }
            $existing_documents = array_values($existing_documents);
        }
        
        if (isset($_FILES['user_documents']) && is_array($_FILES['user_documents']['name'])) {
            foreach ($_FILES['user_documents']['name'] as $key => $value) {
                if ($_FILES['user_documents']['error'][$key] == 0) {
                    $file = array(
                        'name' => $_FILES['user_documents']['name'][$key],
                        'type' => $_FILES['user_documents']['type'][$key],
                        'tmp_name' => $_FILES['user_documents']['tmp_name'][$key],
                        'error' => $_FILES['user_documents']['error'][$key],
                        'size' => $_FILES['user_documents']['size'][$key]
                    );
                    
                    $uploaded_file = $this->handle_file_upload($file, $user_id, 'document');
                    if ($uploaded_file) {
                        $existing_documents[] = $uploaded_file;
                    }
                }
            }
        }
        
        update_user_meta($user_id, 'user_documents', $existing_documents);
    }
    
    private function handle_file_upload($file, $user_id, $type = 'document') {
        $allowed_image_types = array('image/jpeg', 'image/png', 'image/gif', 'image/jpg');
        $allowed_document_types = array(
            'application/pdf',
            'application/msword',
            'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
            'text/plain',
            'application/zip',
            'image/jpeg',
            'image/png',
            'image/gif',
            'image/jpg'
        );
        
        $allowed_extensions = array('jpg', 'jpeg', 'png', 'gif', 'pdf', 'doc', 'docx', 'txt', 'zip');
        
        if ($type == 'image') {
            $allowed_types = $allowed_image_types;
        } else {
            $allowed_types = $allowed_document_types;
        }
        
        $file_type = $file['type'];
        $file_extension = strtolower(pathinfo($file['name'], PATHINFO_EXTENSION));
        
        if (!in_array($file_type, $allowed_types) || !in_array($file_extension, $allowed_extensions)) {
            return false;
        }
        
        if ($file['size'] > 10485760) {
            return false;
        }
        
        $user_dir = $this->upload_dir . $user_id . '/';
        if (!file_exists($user_dir)) {
            wp_mkdir_p($user_dir);
        }
        
        $filename = sanitize_file_name($file['name']);
        $filename = time() . '_' . $filename;
        $destination = $user_dir . $filename;
        
        if (move_uploaded_file($file['tmp_name'], $destination)) {
            chmod($destination, 0644);
            return $destination;
        }
        
        return false;
    }
    
